import React, { useState, useEffect, useMemo } from 'react';
import { Box, Container, Grid, makeStyles, Paper, Table, TableBody, TableCell, TableContainer, TableHead, TableRow } from '@material-ui/core'
import { StudentColumns } from './StudentColumns';
import axios from 'axios'
import { useTable } from 'react-table';

const useStyle = makeStyles(theme => {
    return {
      
      container: {
        maxHeight: 440
      },
      header: {
        padding: theme.spacing(1)
      },
      title: {
        marginTop: '7px'
      },
      search: {
        position: 'relative',
        borderRadius: theme.shape.borderRadius,
        backgroundColor: 'rgba(0,0,0,0.1)',
        '&:hover': {
          backgroundColor: 'rgba(0,0,0,0.25)',
        },
        '& .Mui-focus': {
          backgroundColor: 'rgba(0,0,0,0.25)',
        },
        marginRight: theme.spacing(2),
        marginLeft: 0,
        width: '100%',
        [theme.breakpoints.up('sm')]: {
          marginLeft: theme.spacing(3),
          width: 'auto',
        },
      },
      searchIcon: {
        padding: theme.spacing(0, 2),
        height: '100%',
        position: 'absolute',
        pointerEvents: 'none',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
      },
      inputRoot: {
        color: 'inherit',
      },
      inputInput: {
        padding: theme.spacing(1, 1, 1, 0),
        // vertical padding + font size from searchIcon
        paddingLeft: `calc(1em + ${theme.spacing(4)}px)`,
        transition: theme.transitions.create('width'),
        width: '100%',
        [theme.breakpoints.up('md')]: {
          width: '20ch',
        },
      },
      divider: {
        backgroundColor: '#222'
      }
    }
  })

export default function StudentTable() {

    const classes = useStyle();


  const [students, setStudents] = useState([]);
    function showStudents() {
        axios.get('http://localhost:80/api/getStudents.php')
            .then((response) => {
                setStudents(response.data);
                if (response.data.Status == 'Invalid') {
                    alert('Invalid User');
                } else {
                    // navigate('/teacherDashboard')
                }
            })
    };
    useEffect(() => {
        showStudents();
        console.log('useEffect');
    }, []);


  const columns = useMemo(() => StudentColumns, [])
  const data = useMemo(() => students, [students])

  

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    rows,
    prepareRow
} = useTable({
  columns,
  data
})

  return (
    <Box>
            <section>
              <Container>
                <Paper variant='outlined'>
                  {/* <div className={classes.header}>
                    <Container>
                      <Typography className={classes.title} variant='h4'>
                        Student List
                      </Typography>
                    </Container>
                    <Toolbar>
                      <div className={classes.search}>
                        <div className={classes.searchIcon}>
                          <Search />
                        </div>
                        <InputBase
                          placeholder="Search…"
                          classes={{
                            root: classes.inputRoot,
                            input: classes.inputInput
                          }}
                        />
                      </div>
                    </Toolbar>
                  </div> */}
                  <TableContainer className={classes.container}>
                    <Table {...getTableProps} stickyHeader>
                      <TableHead>
                          {headerGroups.map((headerGroup) => (
                            <TableRow {...headerGroup.getHeaderGroupProps()}>
                              {headerGroup.headers.map((column) => (
                                <TableCell {...column.getHeaderProps()}>
                                  {column.render('Header')}     
                                </TableCell>
                              ))}
                            </TableRow>
                          ))}
                      </TableHead>
                      <TableBody {...getTableBodyProps}>
                        {rows.map((row) => {
                          prepareRow(row)
                          return (
                            <TableRow {...row.getRowProps()}>
                              {row.cells.map((cell) => {
                                return (
                                  <TableCell {...cell.getCellProps()}>
                                    {cell.render('Cell')}
                                  </TableCell>
                                )
                              })}
                            </TableRow>
                          )
                        })}
                      </TableBody>
                    </Table>
                  </TableContainer>
                </Paper>
              </Container>
            </section>
    </Box>
  );
}
